async (params, browser) => {
  // Open place page
  await browser.open(`${params.place_url}`)

  // Wait for place to load
  await browser.waitForSelector('h1', 15000)

  await browser.wait(2000)

  // Click Reviews tab
  const open_reviews = await browser.evaluate(`const reviewsTab = document.querySelector('button[aria-label*="Review"], button[data-tab-index="1"]'); if (reviewsTab) reviewsTab.click(); return { clicked: true }`)

  await browser.wait(2000)

  // Scroll to load reviews
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract reviews
  const reviews = await browser.evaluate(`const reviews = []; const reviewEls = document.querySelectorAll('div.jftiEf[data-review-id], div[data-review-id], div.jftiEf'); const seen = new Set(); for (let i = 0; i < reviewEls.length && reviews.length < 10; i++) { const el = reviewEls[i]; const rid = el.getAttribute('data-review-id') || String(i); if (seen.has(rid)) continue; seen.add(rid); const authorEl = el.querySelector('.d4r55, .d4r55.fontTitleMedium'); const ratingEl = el.querySelector('span[role="img"], .fzvQIb'); const textEl = el.querySelector('.MyEned .wiI7pd, .wiI7pd'); const dateEl = el.querySelector('.rsqaWe, .DU9Pgb .xRkPPb'); const moreBtn = el.querySelector('button[aria-label*="More"], button[jsaction*="review.expand"]'); if (moreBtn) moreBtn.click(); reviews.push({ author: authorEl ? authorEl.textContent.trim() : 'Anonymous', rating: ratingEl ? ratingEl.getAttribute('aria-label') || ratingEl.textContent.trim() || '' : '', text: textEl ? textEl.textContent.trim() : '', date: dateEl ? dateEl.textContent.trim() : '' }); } return { review_count: reviews.length, reviews: reviews }`)

  return reviews
}
